Find Customer.code:
// Look up a specific customer by ID.
// state.data will hold the customer object.
get('customers', $.data.customerId);

// Or — search by email by listing with a filter.
// list('customers', { email: 'jane@example.org', limit: 1 });

Find Subscription.code:
// Look up by subscription ID.
get('subscriptions', $.data.subscriptionId);

// Or — list every subscription for a given customer.
// list('subscriptions', { customer: $.data.customerId, status: 'active' });

Find Balance Transactions.code:
// List recent balance transactions.
list('balance_transactions', {
  // Page size (max 100).
  limit: 25,
});
